  swim:'<path d="M2 17c2 0 2-1 4-1s2 1 4 1 2-1 4-1 2 1 4 1 2-1 4-1M2 21c2 0 2-1 4-1s2 1 4 1 2-1 4-1 2 1 4 1 2-1 4-1M7 13l4-4 4 3 4 1M16 7a2 2 0 1 0 0-4 2 2 0 0 0 0 4Z"/>',
