const icon = (name, size=20) => `<span class="plain-icon"><svg class="icon" width="${size}" height="${size}" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">${PATHS[name] || PATHS.spark}</svg></span>`;
const esc = (value='') => String(value).replace(/[&<>'"]/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[c]));
const iso = d => `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;
const dateAt = value => new Date(`${value}T12:00:00`);
const duration = a => { const [h,m]=a.startTime.split(':').map(Number),[eh,em]=a.endTime.split(':').map(Number); return eh*60+em-h*60-m; };
const fmtDate = value => new Intl.DateTimeFormat('pl-PL',{day:'numeric',month:'long',year:'numeric'}).format(dateAt(value));

const state = {
  screen:'landing', page:'dashboard', user:null, activities:[], search:'', sportFilter:'',
  calendarDate:new Date(), calendarView:'month', selected:null, modalForm:null, modalOriginal:null,
  places:[], weather:null, notificationOpen:false, mobileMenu:false,
  theme:localStorage.getItem('pyf-theme') || 'light',
  settingsSection:'profile',
};

async function request(path, options={}) {
  const response = await fetch(`${API}${path}`, { credentials:'include', headers:{'Content-Type':'application/json',...(options.headers||{})}, ...options });
  if (response.status === 204) return null;
  const data = await response.json().catch(()=>({}));
  if (!response.ok) throw new Error(data.message || 'Nie udało się połączyć z serwerem.');
  return data;
}
const api = {
  me:()=>request('/auth/me'), login:b=>request('/auth/login',{method:'POST',body:JSON.stringify(b)}), logout:()=>request('/auth/logout',{method:'POST'}),
  activities:()=>request('/activities'), create:(b,overlap)=>request(`/activities?allowOverlap=${overlap}`,{method:'POST',body:JSON.stringify(b)}),
  update:(id,b,overlap=true)=>request(`/activities/${id}?allowOverlap=${overlap}`,{method:'PUT',body:JSON.stringify(b)}),
  status:(id,status)=>request(`/activities/${id}/status`,{method:'PATCH',body:JSON.stringify({status})}),
  remove:id=>request(`/activities/${id}`,{method:'DELETE'}), geocode:p=>request(`/geocoding/search?${new URLSearchParams(p)}`),
  reverse:p=>request(`/geocoding/reverse?${new URLSearchParams(p)}`), weather:p=>request(`/weather?${new URLSearchParams(p)}`),
  places:p=>request(`/places?${new URLSearchParams(p)}`), route:b=>request('/routes/running',{method:'POST',body:JSON.stringify(b)}),
  recommendation:b=>request('/recommendations/evaluate',{method:'POST',body:JSON.stringify(b)}),
  profile:b=>request('/users/me',{method:'PUT',body:JSON.stringify(b)}), goal:b=>request('/users/me/activity-goal',{method:'PUT',body:JSON.stringify(b)}),
};

function applyTheme(value=state.theme) {
  const resolved = value === 'system' ? (matchMedia('(prefers-color-scheme:dark)').matches?'dark':'light') : value;
  document.documentElement.dataset.theme = resolved;
}
function toast(message,type='success') {
  document.querySelector('#toast-root').innerHTML=`<div class="static-toast ${type}"><span>${type==='error'?icon('close'):icon('check')}</span><b>${esc(message)}</b><button aria-label="Zamknij">×</button></div>`;
  document.querySelector('.static-toast button').onclick=()=>document.querySelector('#toast-root').innerHTML='';
  clearTimeout(window.__toast); window.__toast=setTimeout(()=>document.querySelector('#toast-root').innerHTML='',4200);
}

function brand(){return `<span class="brand-mark">${icon('spark')}</span><b>PlanYour<span>Fit</span></b>`;}
function renderLanding(){return `<main class="landing">
  <nav class="landing-nav"><a class="brand" href="#top">${brand()}</a><div class="landing-links"><a href="#funkcje">Funkcje</a><a href="#jak-dziala">Jak to działa</a></div><div class="landing-actions"><button class="primary-button compact" id="open-login">Zaloguj się</button></div></nav>
  <section class="hero" id="top"><div class="hero-copy"><div class="hero-badge">${icon('spark',15)} Twój ruch. Twój rytm.</div><h1>Plan treningowy,<br>który <em>zna Twoje potrzeby.</em></h1><p>Zaplanuj aktywność, sprawdź warunki i odkryj najlepsze miejsca w pobliżu. Wszystko w jednym, spokojnym rytmie.</p><div class="hero-actions"><button class="primary-button large" id="hero-login">Zaloguj się do aplikacji ${icon('arrow')}</button><button class="play-button" id="show-how"><span>▶</span> Zobacz jak działa</button></div></div>
  <div class="hero-visual"><div class="visual-orbit orbit-one"></div><div class="visual-orbit orbit-two"></div><div class="runner-card"><div class="runner-sun"></div><img class="hero-biker-image" src="/images/stick_biker.png" alt="Rowerzysta na rowerze"><div class="runner-shadow"></div><div class="weather-float">${icon('sun')}<span><b>18°C</b><small>Idealne warunki</small></span></div><div class="distance-float">${icon('route')}<span><b>7,2 km</b><small>Trasa gotowa</small></span></div></div></div></section>
  <section class="feature-section" id="funkcje"><span class="section-kicker">MNIEJ ZGADYWANIA, WIĘCEJ RUCHU</span><h2>Wszystko, czego potrzebuje<br>Twój aktywny tydzień.</h2><div class="feature-grid"><article><span class="feature-number">01</span><span class="feature-icon lime">${icon('calendar')}</span><h3>Inteligentny kalendarz</h3><p>Planuj treningi w widoku miesiąca, tygodnia lub dnia. Bez chaosu.</p></article><article><span class="feature-number">02</span><span class="feature-icon orange">${icon('cloud')}</span><h3>Pogoda pod kontrolą</h3><p>Sprawdzamy temperaturę, wiatr i opady dokładnie na godzinę treningu.</p></article><article><span class="feature-number">03</span><span class="feature-icon blue">${icon('route')}</span><h3>Trasy i miejsca</h3><p>Znajdź trasę biegową, halę lub basen w wybranym promieniu.</p></article></div></section>
  <section class="steps-section" id="jak-dziala"><div><span class="section-kicker">TO NAPRAWDĘ PROSTE</span><h2>Od pomysłu do treningu<br>w trzech krokach.</h2></div><ol><li><span>1</span><div><b>Wybierz aktywność</b><p>Bieganie, koszykówka lub pływanie.</p></div></li><li><span>2</span><div><b>Dodaj czas i miejsce</b><p>Resztę sprawdzimy za Ciebie.</p></div></li><li><span>3</span><div><b>Ruszaj!</b><p>Z trasą, pogodą i dobrym planem.</p></div></li></ol></section>
  <footer><a class="brand" href="#top">${brand()}</a><p>Ruch dobrze zaplanowany.</p><small>© ${new Date().getFullYear()} PlanYourFit</small></footer></main>`;}

function renderAuth(){return `<main class="auth-page single-login"><button class="auth-back" id="auth-back">${icon('chevronLeft')} Wróć</button><section class="auth-panel"><a class="brand" href="#" id="auth-brand">${brand()}</a><div class="auth-copy"><span class="eyebrow">WITAJ Z POWROTEM</span><h1>Gotowy na dobry tydzień?</h1><p>Zaloguj się na stałe konto pokazowe, aby przejść do planu aktywności.</p></div><div id="auth-error"></div><form class="auth-form" id="login-form">
  <label class="field"><span>E-mail</span><div class="auth-input"><span class="mail-icon">@</span><input name="email" type="email" value="${DEMO.email}" required></div></label>
  <label class="field"><span>Hasło</span><div class="auth-input"><span class="lock-icon">⌁</span><input name="password" type="text" value="${DEMO.password}" required></div></label>
  <button type="button" class="primary-button auth-submit" id="login-submit">Zaloguj się ${icon('arrow')}</button>
  <button type="button" class="secondary-button full" id="quick-demo-login">Wejdź na domyślne konto</button></form>
  <div class="fixed-account"><b>Stałe konto prezentacyjne</b><br>E-mail: <code>${DEMO.email}</code><br>Hasło: <code>${DEMO.password}</code></div>
  <small class="auth-legal">To lokalna wersja pokazowa — dane logowania nie są zabezpieczone.</small></section><aside class="auth-art"><div class="art-track"><span></span><span></span><span></span></div></aside></main>`;}

function notifications(){
  const now=`${iso(new Date())}${new Date().toTimeString().slice(0,5)}`;
  const confirmations=state.activities.filter(a=>(a.status||'planned')==='planned'&&`${a.activityDate}${a.endTime}`<=now).map(a=>({type:'confirmation',activity:a,title:`Czy trening „${a.title}” się odbył?`,body:`${fmtDate(a.activityDate)}, ${a.startTime}–${a.endTime}`}));
  const upcoming=state.activities.filter(a=>(a.status||'planned')==='planned'&&`${a.activityDate}${a.endTime}`>now).sort((a,b)=>`${a.activityDate}${a.startTime}`.localeCompare(`${b.activityDate}${b.startTime}`)).slice(0,6).map(a=>({type:'activity',activity:a,title:a.title,body:`${fmtDate(a.activityDate)} o ${a.startTime}`}));
  return [...confirmations,...upcoming];
}
function notificationList(){const list=notifications();if(!list.length)return `<div class="notification-empty">${icon('check')}<b>Wszystko gotowe</b><span>Nie masz teraz przypomnień.</span></div>`;return list.map((n,i)=>n.type==='confirmation'?`<article class="notification-item notification-confirmation"><span class="notification-symbol confirmation">${icon('clock',18)}</span><span><b>${esc(n.title)}</b><small>${esc(n.body)}</small><span class="notification-confirm-actions"><button class="confirm-yes" data-status-index="${i}" data-status="completed">${icon('check',14)} Tak</button><button data-status-index="${i}" data-status="cancelled">${icon('close',14)} Nie</button></span></span></article>`:`<button class="notification-item" data-notification-index="${i}"><span class="notification-symbol activity">${icon('calendar',18)}</span><span><b>${esc(n.title)}</b><small>${esc(n.body)}</small></span>${icon('chevronRight',16)}</button>`).join('');}

function filteredActivities(){const q=state.search.toLocaleLowerCase('pl-PL');return state.activities.filter(a=>(!state.sportFilter||a.activityType===state.sportFilter)&&(!q||a.title.toLocaleLowerCase('pl-PL').includes(q)));}
function appShell(content){const nav=[['dashboard','home','Pulpit'],['analytics','chart','Statystyki'],['settings','settings','Ustawienia']];return `<div class="app-shell"><aside class="sidebar ${state.mobileMenu?'open':''}"><div class="sidebar-top"><button class="brand brand-button" data-page="dashboard">${brand()}</button><button class="icon-button sidebar-close" id="close-menu">${icon('close')}</button></div><nav>${nav.map(([p,i,l])=>`<button data-page="${p}" class="${state.page===p?'active':''}">${icon(i)}<span>${l}</span></button>`).join('')}</nav><div class="sidebar-promo"><span>${icon('spark')}</span><b>Dobry plan to pół sukcesu.</b><p>Reszta to pierwszy krok.</p></div><button class="logout-button" id="logout">${icon('logout')} Wyloguj się</button></aside>${state.mobileMenu?'<div class="sidebar-overlay" id="close-overlay"></div>':''}<div class="app-main"><header class="topbar"><button class="icon-button menu-button" id="open-menu">${icon('menu')}</button><div class="topbar-search">${icon('search')}<input id="activity-search" value="${esc(state.search)}" placeholder="Szukaj po nazwie…"><select id="sport-filter"><option value="">Wszystkie</option>${Object.entries(SPORTS).map(([k,s])=>`<option value="${k}" ${state.sportFilter===k?'selected':''}>${s.label}</option>`).join('')}</select></div><div class="topbar-actions"><button class="icon-button" id="theme-toggle" title="Zmień motyw">${icon(state.theme==='dark'?'sun':'moon')}</button><div class="notification-wrap"><button class="icon-button notification ${state.notificationOpen?'active':''}" id="notification-toggle">${icon('bell')}${notifications().length?'<i></i>':''}</button>${state.notificationOpen?`<section class="notification-panel"><header><div><span class="eyebrow">POWIADOMIENIA</span><h3>Twój plan</h3></div><button class="icon-button" id="notification-close">${icon('close',17)}</button></header><div class="notification-list">${notificationList()}</div></section>`:''}</div><button class="profile-button" data-page="settings"><span>${esc(state.user.name.slice(0,2).toUpperCase())}</span><div><b>${esc(state.user.name)}</b><small>Konto pokazowe</small></div>${icon('chevronRight',15)}</button></div></header><main>${content}</main><nav class="mobile-nav">${[['dashboard','home','Pulpit'],['dashboard','calendar','Kalendarz'],['analytics','chart','Statystyki'],['settings','settings','Ustawienia']].map(([p,i,l])=>`<button data-page="${p}" class="${state.page===p?'active':''}">${icon(i)}<small>${l}</small></button>`).join('')}<button class="mobile-add" data-add="${iso(new Date())}">${icon('plus')}</button></nav></div></div>`;}

function statsCard(iconName,tone,label,value,suffix=''){return `<article class="stat-card"><span class="stat-icon ${tone}">${icon(iconName)}</span><div><small>${label}</small><strong>${value}<em>${suffix}</em></strong></div></article>`;}
function renderCalendar(){const acts=filteredActivities(),date=state.calendarDate,today=new Date();let body='';if(state.calendarView==='month'){
  const first=new Date(date.getFullYear(),date.getMonth(),1),start=new Date(first);start.setDate(1-((first.getDay()+6)%7));const days=Array.from({length:42},(_,i)=>{const d=new Date(start);d.setDate(start.getDate()+i);return d;});
  body=`<div class="month-grid">${['Pon','Wt','Śr','Czw','Pt','Sob','Ndz'].map(d=>`<div class="weekday">${d}</div>`).join('')}${days.map(d=>{const day=iso(d),events=acts.filter(a=>a.activityDate===day);return `<div class="calendar-day ${d.getMonth()!==date.getMonth()?'outside':''} ${iso(d)===iso(today)?'today':''}"><button class="day-number" data-add="${day}">${d.getDate()}</button><div class="day-events">${events.slice(0,3).map(a=>`<button class="event-pill ${SPORTS[a.activityType].color}" data-select="${a.id}"><span class="event-dot"></span><span class="event-time">${a.startTime}</span><span class="event-name">${esc(a.title)}</span></button>`).join('')}${events.length>3?`<span class="more-events">+${events.length-3} więcej</span>`:''}</div></div>`}).join('')}</div>`;
}else{const start=new Date(date);if(state.calendarView==='week')start.setDate(date.getDate()-((date.getDay()+6)%7));const count=state.calendarView==='day'?1:7,days=Array.from({length:count},(_,i)=>{const d=new Date(start);d.setDate(start.getDate()+i);return d;});const hours=Array.from({length:15},(_,i)=>i+6);body=`<div class="schedule ${count===1?'single-day':''}"><div class="schedule-head"><div></div><div class="schedule-days" style="--days:${count}">${days.map(d=>`<button class="${iso(d)===iso(today)?'active':''}" data-add="${iso(d)}"><span>${['Ndz','Pon','Wt','Śr','Czw','Pt','Sob'][d.getDay()]}</span><strong>${d.getDate()}</strong></button>`).join('')}</div></div><div class="schedule-body"><div class="hour-labels">${hours.map(h=>`<span>${String(h).padStart(2,'0')}:00</span>`).join('')}</div><div class="schedule-columns" style="--days:${count}">${days.map(d=>`<div class="schedule-column">${hours.map(()=>'<div class="hour-line"></div>').join('')}${acts.filter(a=>a.activityDate===iso(d)).map(a=>{const [h,m]=a.startTime.split(':').map(Number),[eh,em]=a.endTime.split(':').map(Number),top=((h-6)*60+m)/900*100,height=Math.max(5,(eh*60+em-h*60-m)/900*100);return `<button class="schedule-event ${SPORTS[a.activityType].color}" style="top:${top}%;height:${height}%" data-select="${a.id}"><b>${a.startTime}</b>${esc(a.title)}</button>`}).join('')}</div>`).join('')}</div></div></div>`;}
const title=state.calendarView==='month'?new Intl.DateTimeFormat('pl-PL',{month:'long',year:'numeric'}).format(date):fmtDate(iso(date));return `<section class="card calendar-card"><div class="calendar-toolbar"><div class="calendar-title"><button class="icon-button" data-calendar-move="-1">${icon('chevronLeft')}</button><h2>${title}</h2><button class="icon-button" data-calendar-move="1">${icon('chevronRight')}</button><button class="today-button" id="calendar-today">Dziś</button></div><div class="segmented">${[['month','Miesiąc'],['week','Tydzień'],['day','Dzień']].map(([v,l])=>`<button data-calendar-view="${v}" class="${state.calendarView===v?'active':''}">${l}</button>`).join('')}</div></div>${body}</section>`;}

function renderDashboard(){const now=new Date(),month=state.activities.filter(a=>{const d=dateAt(a.activityDate);return d.getMonth()===now.getMonth()&&d.getFullYear()===now.getFullYear()&&a.status==='completed'}),minutes=month.reduce((s,a)=>s+duration(a),0),distance=month.filter(a=>a.activityType==='running').reduce((s,a)=>s+Number(a.details?.actualDistanceKm||a.details?.targetDistanceKm||0),0),counts=Object.keys(SPORTS).map(type=>[type,month.filter(a=>a.activityType===type).length]).sort((a,b)=>b[1]-a[1]),upcoming=filteredActivities().filter(a=>(a.status||'planned')==='planned'&&a.activityDate>=iso(now)).sort((a,b)=>`${a.activityDate}${a.startTime}`.localeCompare(`${b.activityDate}${b.startTime}`)).slice(0,4);return `<div class="dashboard-content"><header class="page-intro"><div><span class="eyebrow">${new Intl.DateTimeFormat('pl-PL',{weekday:'long',day:'numeric',month:'long'}).format(now).toUpperCase()}</span><h1>${now.getHours()<12?'Dzień dobry':now.getHours()<18?'Miłego popołudnia':'Dobry wieczór'}, ${esc(state.user.name)}! <span>👋</span></h1><p>Twój tydzień wygląda dobrze. Każdy ruch się liczy.</p></div><button class="primary-button add-main" data-add="${iso(now)}">${icon('plus')} Dodaj aktywność</button></header><section class="stats-grid">${statsCard('calendar','lime','Ukończone w tym miesiącu',month.length)}${statsCard('clock','purple','Łączny czas',Math.floor(minutes/60),` h ${minutes%60} min`)}${statsCard('route','orange','Przebiegnięty dystans',distance.toFixed(1),' km')}${statsCard('spark','blue','Najczęstsza aktywność',counts[0][1]?SPORTS[counts[0][0]].short:'—')}</section>${renderCalendar()}<div class="dashboard-lower"><section class="card upcoming-card"><div class="section-heading"><div><span class="eyebrow">NA HORYZONCIE</span><h2>Najbliższe aktywności</h2></div></div><div class="upcoming-list">${upcoming.length?upcoming.map(a=>{const s=SPORTS[a.activityType];return `<button class="upcoming-item" data-select="${a.id}"><span class="date-tile ${s.color}"><b>${dateAt(a.activityDate).getDate()}</b><small>${new Intl.DateTimeFormat('pl-PL',{month:'short'}).format(dateAt(a.activityDate)).replace('.','')}</small></span><span class="upcoming-info"><b>${esc(a.title)}</b><small>${icon('clock',14)}${a.startTime}–${a.endTime}<i></i>${icon('pin',14)}${esc(a.locationAddress)}</small></span><span class="sport-mini ${s.color}">${icon(s.icon)}</span>${icon('chevronRight',18)}</button>`}).join(''):`<div class="empty-state"><span>${icon('calendar')}</span><b>Spokojny kalendarz</b><p>Dodaj pierwszą aktywność.</p></div>`}</div></section>${renderWeekly()}</div></div>`;}
function renderWeekly(){const today=new Date(),monday=new Date(today);monday.setDate(today.getDate()-((today.getDay()+6)%7));const days=Array.from({length:7},(_,i)=>{const d=new Date(monday);d.setDate(monday.getDate()+i);return d}),values=days.map(d=>state.activities.filter(a=>a.status==='completed'&&a.activityDate===iso(d)).reduce((s,a)=>s+duration(a),0)),max=Math.max(90,...values);return `<section class="card weekly-card"><div class="section-heading"><div><span class="eyebrow">TEN TYDZIEŃ</span><h2>Twój rytm aktywności</h2></div><span class="chart-total">${(values.reduce((a,b)=>a+b,0)/60).toFixed(1)}<small> godz.</small></span></div><div class="bar-chart">${values.map((v,i)=>`<div class="bar-column"><div class="bar-track"><span class="${i===((today.getDay()+6)%7)?'today':''}" style="height:${Math.max(v?14:3,v/max*100)}%">${v?`<i>${v} min</i>`:''}</span></div><small>${['Pn','Wt','Śr','Cz','Pt','So','Nd'][i]}</small></div>`).join('')}</div><div class="weekly-legend"><span><i class="lime-dot"></i> Ukończone</span><span>${icon('spark',14)} Regularność buduje formę</span></div></section>`;}

function renderAnalytics(){const now=new Date(),items=state.activities.filter(a=>{const d=dateAt(a.activityDate);return a.status==='completed'&&d.getMonth()===now.getMonth()&&d.getFullYear()===now.getFullYear()}),minutes=items.reduce((s,a)=>s+duration(a),0),distance=items.filter(a=>a.activityType==='running').reduce((s,a)=>s+Number(a.details?.actualDistanceKm||a.details?.targetDistanceKm||0),0),goal=Number(state.user.monthlyActivityGoal||12),progress=Math.min(100,Math.round(items.length/goal*100)),max=Math.max(1,...Object.keys(SPORTS).map(t=>items.filter(a=>a.activityType===t).length));return `<div class="analytics-page"><header class="page-intro"><div><span class="eyebrow">PODSUMOWANIE MIESIĄCA</span><h1>Twój ruch w liczbach</h1><p>Małe kroki układają się w całkiem dobrą historię.</p></div></header><div class="analytics-grid"><section class="card analytics-hero"><div><span class="eyebrow">${new Intl.DateTimeFormat('pl-PL',{month:'long'}).format(now).toUpperCase()}</span><h2>${items.length} ukończonych aktywności</h2><p>Łącznie ${Math.floor(minutes/60)} h ${minutes%60} min potwierdzonego ruchu.</p><form class="goal-editor" id="goal-form"><label class="goal-control"><span>Miesięczny cel</span><div class="goal-stepper"><button type="button" data-goal-delta="-1" aria-label="Zmniejsz cel">−</button><input type="number" name="goal" min="1" max="100" step="1" value="${goal}" inputmode="numeric"><button type="button" data-goal-delta="1" aria-label="Zwiększ cel">+</button></div><small>aktywności</small></label><button class="goal-submit">Ustaw cel</button></form></div><div class="progress-ring" style="--progress:${progress}%"><span><b>${progress}%</b><small>${items.length} z ${goal}</small></span></div></section><section class="card sport-breakdown"><div class="section-heading"><div><span class="eyebrow">AKTYWNOŚCI</span><h2>Ulubione dyscypliny</h2></div></div>${Object.entries(SPORTS).map(([t,s])=>{const count=items.filter(a=>a.activityType===t).length;return `<div class="sport-bar"><span class="sport-icon ${s.color}">${icon(s.icon)}</span><div><p><b>${s.label}</b><small>${count} treningi</small></p><i><em class="${s.color}" style="width:${count/max*100}%"></em></i></div></div>`}).join('')}</section><section class="card milestone-card"><span class="milestone-icon">${icon('route',30)}</span><div><span class="eyebrow">DYSTANS BIEGOWY</span><h2>${distance.toFixed(1)} km</h2><p>To mniej więcej ${Math.round(distance/42.195*100)}% maratonu.</p></div></section><section class="card insight-card">${icon('spark')}<div><span class="eyebrow">WSKAZÓWKA</span><h3>Regularność wygrywa z intensywnością.</h3><p>Zaplanuj kolejną aktywność już dziś.</p></div></section></div></div>`;}

function renderSettings(){const u=state.user,sections=[['profile','user','Profil'],['location','pin','Lokalizacja'],['appearance','moon','Wygląd'],['notifications','bell','Powiadomienia']];return `<div class="settings-page"><header class="page-intro"><div><span class="eyebrow">TWOJE PREFERENCJE</span><h1>Ustawienia</h1><p>Dopasuj PlanYourFit do swojego rytmu.</p></div></header><div class="settings-layout"><nav class="settings-nav">${sections.map(([id,i,l])=>`<button type="button" data-settings-link="${id}" class="${state.settingsSection===id?'active':''}">${icon(i)} ${l}</button>`).join('')}</nav><div class="settings-main"><form class="card settings-card settings-anchor" id="profile-form" data-settings-section="profile"><div class="settings-heading"><span class="profile-avatar">${esc(u.name.slice(0,2).toUpperCase())}</span><div><h2>Dane profilu</h2><p>Podstawowe informacje o koncie pokazowym.</p></div></div><div class="form-grid"><label class="field"><span>Imię</span><input name="name" value="${esc(u.name)}" required></label><label class="field"><span>E-mail</span><input name="email" type="email" value="${esc(u.email)}" required></label><div class="field span-2 settings-anchor" data-settings-section="location"><span>Domyślna lokalizacja</span><div class="field-with-icon">${icon('pin')}<input name="defaultLocation" value="${esc(u.defaultLocation||'')}" placeholder="Np. Warszawa"></div><button type="button" class="text-button settings-location-button" id="settings-geolocation">${icon('target')} Użyj mojej lokalizacji</button></div><label class="field"><span>Kod pocztowy</span><input name="defaultPostalCode" value="${esc(u.defaultPostalCode||'')}" placeholder="00-000" pattern="\d{2}-\d{3}"></label><label class="field"><span>Domyślny promień</span><div class="input-suffix"><input name="preferredRadiusKm" type="number" min="1" max="50" value="${u.preferredRadiusKm||25}"><b>km</b></div></label></div><div class="theme-setting settings-anchor" data-settings-section="appearance"><span>Motyw aplikacji</span><div class="theme-options">${[['light','Jasny','sun'],['dark','Ciemny','moon'],['system','Systemowy','settings']].map(([v,l,i])=>`<button type="button" data-theme="${v}" class="${state.theme===v?'active':''}">${icon(i)}<b>${l}</b>${state.theme===v?icon('check',15):''}</button>`).join('')}</div></div><input type="hidden" name="theme" value="${state.theme}"><input type="hidden" name="defaultLocationLat" value="${u.defaultLocationLat??''}"><input type="hidden" name="defaultLocationLng" value="${u.defaultLocationLng??''}"><div class="settings-footer"><button class="primary-button">Zapisz ustawienia</button></div></form><section class="card settings-card settings-notifications settings-anchor" data-settings-section="notifications"><div class="settings-heading"><span class="settings-symbol">${icon('bell')}</span><div><h2>Powiadomienia</h2><p>Przypomnienia i potwierdzanie treningów.</p></div></div><div class="settings-notification-list">${notificationList()}</div></section><section class="card settings-card compact-card"><div class="settings-heading"><span class="settings-symbol">•••</span><div><h2>Logowanie pokazowe</h2><p>Hasło jest stałe i jawne.</p></div></div><div class="settings-demo-note">${DEMO.email} / ${DEMO.password}<br>Zmiana hasła i rejestracja są celowo wyłączone.</div></section></div></div></div>`;}

function emptyForm(date=iso(new Date())){const u=state.user||{};return {activityType:'running',title:'Poranny bieg',activityDate:date,startTime:'07:30',endTime:'08:15',locationAddress:u.defaultLocation||'',postalCode:u.defaultPostalCode||'',locationLat:u.defaultLocationLat??null,locationLng:u.defaultLocationLng??null,note:'',searchRadiusKm:u.preferredRadiusKm||25,repeatWeekly:false,repeatCount:4,details:{targetDistanceKm:5,paceMinPerKm:6,courtType:'outdoor',selectedPlaceId:null}};}
function openActivity(date,activity=null){state.modalOriginal=activity;state.modalForm=activity?{...emptyForm(activity.activityDate),...structuredClone(activity),repeatWeekly:false,repeatCount:4,details:{...emptyForm().details,...structuredClone(activity.details||{})}}:emptyForm(date);state.places=[];state.weather=activity?.details?.weather||null;renderOverlay();}
function field(name,label,type='text',extra=''){return `<label class="field"><span>${label}</span><input name="${name}" type="${type}" value="${esc(state.modalForm[name]??'')}" ${extra}></label>`;}
function renderActivityModal(){const f=state.modalForm,edit=Boolean(state.modalOriginal),overlap=state.activities.find(a=>a.id!==state.modalOriginal?.id&&a.activityDate===f.activityDate&&a.startTime<f.endTime&&a.endTime>f.startTime);return `<div class="modal-backdrop"><div class="modal activity-modal"><div class="modal-header"><div><span class="eyebrow">${edit?'EDYCJA PLANU':'NOWA AKTYWNOŚĆ'}</span><h2>${edit?'Zmień szczegóły':'Zaplanuj ruch'}</h2></div><button class="icon-button" data-close-modal>${icon('close')}</button></div><form id="activity-form" class="activity-form"><div class="modal-scroll"><div class="sport-picker">${Object.entries(SPORTS).map(([k,s])=>`<button type="button" data-sport="${k}" class="sport-option ${f.activityType===k?'active':''}"><span class="sport-icon ${s.color}">${icon(s.icon)}</span><b>${s.label}</b>${f.activityType===k?`<span class="selected-check">${icon('check',13)}</span>`:''}</button>`).join('')}</div><div class="form-grid"><label class="field span-2"><span>Nazwa aktywności</span><input name="title" value="${esc(f.title)}" required></label>${field('activityDate','Data','date','required')}<div class="time-fields">${field('startTime','Od','time','required')}${field('endTime','Do','time','required')}</div></div>${overlap?`<div class="inline-alert warning">${icon('clock')}<div><b>Termin nachodzi na „${esc(overlap.title)}”</b><span>Zapis jest możliwy, sprawdź godziny.</span></div></div>`:''}${f.activityType==='basketball'?`<div class="dynamic-section"><div class="section-label">Rodzaj boiska</div><div class="choice-row"><button type="button" data-court="outdoor" class="${f.details.courtType==='outdoor'?'active':''}">Na zewnątrz</button><button type="button" data-court="indoor" class="${f.details.courtType==='indoor'?'active':''}">Na hali</button></div></div>`:''}${f.activityType==='running'?`<div class="dynamic-section running-fields"><label class="field"><span>Dystans</span><div class="input-suffix"><input name="targetDistanceKm" type="number" min="0.5" max="100" step="0.5" value="${f.details.targetDistanceKm}"><b>km</b></div></label><label class="field"><span>Tempo</span><div class="input-suffix"><input name="paceMinPerKm" type="number" min="2" max="20" step="0.1" value="${f.details.paceMinPerKm}"><b>min/km</b></div></label></div>`:''}<div class="location-block"><div class="location-heading"><div><span class="section-label">Lokalizacja</span><p>Podaj adres lub użyj swojej pozycji</p></div><button type="button" class="text-button" id="modal-geolocation">${icon('target')} Użyj mojej lokalizacji</button></div><div class="location-fields"><label class="field location-input">${icon('pin')}<input name="locationAddress" value="${esc(f.locationAddress)}" placeholder="Adres lub nazwa miejsca" required></label>${field('postalCode','Kod pocztowy','text','pattern="\\d{2}-\\d{3}" required')}</div><div class="range-row"><label>Promień wyszukiwania <b>${f.searchRadiusKm} km</b></label><input name="searchRadiusKm" type="range" min="1" max="50" value="${f.searchRadiusKm}"></div>${(f.activityType==='swimming'||(f.activityType==='basketball'&&f.details.courtType==='indoor'))?`<button type="button" class="secondary-button full" id="find-places">${icon('search')} Znajdź ${f.activityType==='swimming'?'baseny':'hale'} w pobliżu</button>`:''}${state.places.length?`<div class="places-list">${state.places.map(p=>`<button type="button" data-place="${esc(p.id)}" class="${f.details.selectedPlaceId===p.id?'selected':''}"><span class="place-icon">${icon(f.activityType==='swimming'?'swim':'basketball')}</span><span><b>${esc(p.name)}</b><small>${esc(p.address)}</small></span><strong class="place-distance">${p.distanceKm} km</strong></button>`).join('')}</div>`:''}</div><section class="weather-preview"><div class="weather-preview-heading"><div><span class="section-label">Pogoda podczas aktywności</span><p>${f.activityDate} · ${f.startTime}–${f.endTime}</p></div><button type="button" class="text-button" id="check-weather">Odśwież</button></div>${state.weather?`<div class="weather-preview-grid"><div>${icon('cloud')}<span><small>Warunki</small><b>${state.weather.thunderstorm?'Burza':Number(state.weather.precipitation)>0?'Opady':'Bezchmurnie'}</b></span></div><div><small>Temperatura</small><b>${state.weather.temperature??'—'}°C</b></div><div><small>Wiatr maks.</small><b>${state.weather.windSpeed??'—'} km/h</b></div><div><small>Opady</small><b>${state.weather.precipitation??0} mm</b></div></div>`:'<p class="weather-preview-hint">Kliknij „Odśwież”, aby pobrać prognozę Open-Meteo.</p>'}</section><label class="field"><span>Notatka <em>opcjonalnie</em></span><textarea name="note" rows="3">${esc(f.note)}</textarea></label>${!edit?`<div class="repeat-row"><label class="switch"><input name="repeatWeekly" type="checkbox" ${f.repeatWeekly?'checked':''}><span></span></label><div><b>Powtarzaj co tydzień</b><small>Dodaj serię do kalendarza</small></div><select name="repeatCount"><option value="4">4 tygodnie</option><option value="8">8 tygodni</option><option value="12">12 tygodni</option></select></div>`:''}</div><div class="modal-footer"><button type="button" class="ghost-button" data-close-modal>Anuluj</button><button class="primary-button">${icon('check')} ${edit?'Zapisz zmiany':'Dodaj do kalendarza'}</button></div></form></div></div>`;}

function sampleWaypoints(coords,limit=8){if(coords.length<=2)return[];const result=[],count=Math.min(limit,coords.length-2);for(let i=1;i<=count;i+=1){const raw=Math.round(i*(coords.length-1)/(count+1)),index=Math.max(1,Math.min(coords.length-2,raw)),point=coords[index];if(point&&!result.some(p=>Math.abs(p[0]-point[0])<0.00001&&Math.abs(p[1]-point[1])<0.00001))result.push(point);}return result;}
function googleMapsUrl(a){let coords=(a.details?.routeGeojson?.geometry?.coordinates||[]).filter(c=>Array.isArray(c)&&c.length>=2&&Number.isFinite(Number(c[0]))&&Number.isFinite(Number(c[1])));if(coords.length<2&&a.activityType==='running'&&a.locationLat&&a.locationLng){const lat=Number(a.locationLat),lng=Number(a.locationLng),distance=Number(a.details?.targetDistanceKm||a.details?.actualDistanceKm||5),delta=Math.max(.006,Math.min(.035,distance/111/2));coords=[[lng,lat],[lng+delta*.8,lat+delta],[lng+delta*1.35,lat],[lng,lat]];}if(coords.length<2)return null;const f=([lng,lat])=>`${Number(lat).toFixed(6)},${Number(lng).toFixed(6)}`,same=(a,b)=>Math.abs(Number(a[0])-Number(b[0]))<0.00001&&Math.abs(Number(a[1])-Number(b[1]))<0.00001,start=coords[0],end=coords[coords.length-1],isLoop=same(start,end);const destination=isLoop?start:end,waypoints=sampleWaypoints(coords,isLoop?9:8);const params=new URLSearchParams({api:'1',origin:f(start),destination:f(destination),travelmode:'walking'});if(waypoints.length)params.set('waypoints',waypoints.map(f).join('|'));return `https://www.google.com/maps/dir/?${params}`;}
function renderDetails(){const a=state.selected,s=SPORTS[a.activityType],w=a.details?.weather||{},rec=a.details?.recommendation||{status:'good',message:'Warunki są korzystne.'},url=googleMapsUrl(a);return `<div class="modal-backdrop"><div class="modal details-modal"><div class="details-hero ${s.color}"><button class="icon-button details-close" data-close-modal>${icon('close')}</button><span class="sport-icon ${s.color}">${icon(s.icon,30)}</span><div class="details-title-row"><h2>${esc(a.title)}</h2><span class="status-chip ${a.status||'planned'}">${a.status==='completed'?'Ukończona':a.status==='cancelled'?'Anulowana':'Zaplanowana'}</span></div><p class="details-date">${fmtDate(a.activityDate)} · ${a.startTime}–${a.endTime}</p></div><div class="modal-scroll"><div class="recommendation ${rec.status||'good'}"><span>${icon(rec.status==='bad'?'close':'check')}</span><div><b>${rec.status==='warning'?'Ostrożnie':rec.status==='bad'?'Niezalecane':'Warunki sprzyjają'}</b><p>${esc(rec.message)}</p></div></div><div class="details-grid"><div class="detail-item"><span class="detail-icon">${icon('pin')}</span><div><small>Lokalizacja</small><b>${esc(a.postalCode||'')} · ${esc(a.locationAddress)}</b></div></div><div class="detail-item"><span class="detail-icon">${icon('clock')}</span><div><small>Czas trwania</small><b>${duration(a)} min</b></div></div>${a.activityType==='running'?`<div class="detail-item"><span class="detail-icon">${icon('route')}</span><div><small>Dystans</small><b>${a.details?.actualDistanceKm||a.details?.targetDistanceKm||5} km</b></div></div><div class="detail-item"><span class="detail-icon">${icon('target')}</span><div><small>Tempo</small><b>${a.details?.paceMinPerKm||6} min/km</b></div></div>`:''}</div><div class="mini-map"><div id="route-map" class="route-map-canvas"></div><span class="map-label">${esc(a.locationAddress)}</span></div>${url?`<div class="route-external-actions"><div class="route-action-buttons"><button class="secondary-button" id="regenerate-route">${icon('route')} Zmień trasę</button><a class="secondary-button" href="${url}" target="_blank" rel="noreferrer">${icon('route')} Otwórz w Google Maps</a></div></div>`:''}${a.activityType!=='swimming'?`<div class="weather-strip"><div>${icon('cloud')}<span><small>Pogoda</small><b>${w.temperature??'—'}°C</b></span></div><div><small>Wiatr</small><b>${w.windSpeed??'—'} km/h</b></div><div><small>Opady</small><b>${w.precipitation??0} mm</b></div></div>`:''}${a.note?`<div class="note-box"><small>Twoja notatka</small><p>${esc(a.note)}</p></div>`:''}</div><div class="modal-footer details-actions"><button class="danger-button" id="delete-activity">${icon('trash')} Usuń</button><button class="secondary-button" id="edit-activity">${icon('edit')} Edytuj</button><button class="primary-button" data-close-modal>Gotowe</button></div></div></div>`;}

function renderOverlay(){const root=document.querySelector('#overlay-root');root.innerHTML=state.modalForm?renderActivityModal():state.selected?renderDetails():'';bindOverlay();if(state.selected)setTimeout(drawMap,0);}
function drawMap(){const a=state.selected,el=document.querySelector('#route-map');if(!el)return;const coords=(a.details?.routeGeojson?.geometry?.coordinates||[]).map(([lng,lat])=>[lat,lng]),fallback=[Number(a.locationLat)||52.2297,Number(a.locationLng)||21.0122],points=coords.length?coords:[fallback];if(!window.L){el.innerHTML='<div class="map-fallback">Mapa wymaga połączenia z internetem.</div>';return;}const map=L.map(el,{scrollWheelZoom:false}).setView(points[0],15);L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png',{attribution:'© OpenStreetMap contributors'}).addTo(map);if(coords.length>1){L.polyline(coords,{color:'#507f35',weight:5}).addTo(map);map.fitBounds(coords,{padding:[22,22]});}L.circleMarker(points[0],{radius:7,color:'#173a33',fillColor:'#c9f258',fillOpacity:1}).addTo(map).bindTooltip('Start i meta',{permanent:true,direction:'top'});}

function render(){applyTheme();let html=state.screen==='landing'?renderLanding():state.screen==='auth'?renderAuth():appShell(state.page==='analytics'?renderAnalytics():state.page==='settings'?renderSettings():renderDashboard());document.querySelector('#app').innerHTML=html;bind();renderOverlay();}
function bind(){
  document.querySelectorAll('#open-login,#hero-login').forEach(b=>b.onclick=()=>{state.screen='auth';render()});document.querySelector('#show-how')?.addEventListener('click',()=>document.querySelector('#jak-dziala')?.scrollIntoView({behavior:'smooth'}));document.querySelectorAll('#auth-back,#auth-brand').forEach(b=>b.onclick=e=>{e.preventDefault();state.screen='landing';render()});
  document.querySelector('#login-form')?.addEventListener('submit',login);document.querySelector('#login-submit')?.addEventListener('click',login);document.querySelector('#quick-demo-login')?.addEventListener('click',()=>enterDemoAccount());document.querySelectorAll('[data-page]').forEach(b=>b.onclick=()=>{state.page=b.dataset.page;state.mobileMenu=false;state.notificationOpen=false;render()});
  document.querySelector('#logout')?.addEventListener('click',logout);document.querySelector('#open-menu')?.addEventListener('click',()=>{state.mobileMenu=true;render()});document.querySelectorAll('#close-menu,#close-overlay').forEach(b=>b.onclick=()=>{state.mobileMenu=false;render()});
  document.querySelector('#theme-toggle')?.addEventListener('click',()=>{state.theme=state.theme==='dark'?'light':'dark';localStorage.setItem('pyf-theme',state.theme);render()});document.querySelector('#notification-toggle')?.addEventListener('click',()=>{state.notificationOpen=!state.notificationOpen;render()});document.querySelector('#notification-close')?.addEventListener('click',()=>{state.notificationOpen=false;render()});
  document.querySelector('#activity-search')?.addEventListener('input',e=>{state.search=e.target.value;renderPageOnly()});document.querySelector('#sport-filter')?.addEventListener('change',e=>{state.sportFilter=e.target.value;render()});
  document.querySelectorAll('[data-add]').forEach(b=>b.onclick=e=>{e.preventDefault();e.stopPropagation();openActivity(b.dataset.add)});document.querySelectorAll('[data-select]').forEach(b=>b.onclick=e=>{e.preventDefault();e.stopPropagation();state.selected=state.activities.find(a=>String(a.id)===b.dataset.select);renderOverlay()});
  document.querySelectorAll('[data-calendar-view]').forEach(b=>b.onclick=()=>{state.calendarView=b.dataset.calendarView;render()});document.querySelectorAll('[data-calendar-move]').forEach(b=>b.onclick=()=>{const d=new Date(state.calendarDate),dir=Number(b.dataset.calendarMove);state.calendarView==='month'?d.setMonth(d.getMonth()+dir):d.setDate(d.getDate()+dir*(state.calendarView==='week'?7:1));state.calendarDate=d;render()});document.querySelector('#calendar-today')?.addEventListener('click',()=>{state.calendarDate=new Date();render()});
  document.querySelector('#goal-form')?.addEventListener('submit',saveGoal);document.querySelectorAll('[data-goal-delta]').forEach(b=>b.onclick=changeGoalInput);document.querySelector('#profile-form')?.addEventListener('submit',saveProfile);document.querySelector('#profile-form')?.addEventListener('input',syncProfileForm);document.querySelector('#profile-form')?.addEventListener('change',syncProfileForm);document.querySelector('#settings-geolocation')?.addEventListener('click',e=>{e.preventDefault();syncProfileForm();useGeolocation(true)});document.querySelectorAll('[data-theme]').forEach(b=>b.onclick=()=>{syncProfileForm();state.theme=b.dataset.theme;localStorage.setItem('pyf-theme',state.theme);render()});bindSettingsNavigation();bindNotifications();
}
function renderPageOnly(){if(state.screen!=='app')return;const main=document.querySelector('.app-main main');if(main)main.innerHTML=state.page==='analytics'?renderAnalytics():state.page==='settings'?renderSettings():renderDashboard();bind();}
function setSettingsSection(id){state.settingsSection=id;document.querySelectorAll('[data-settings-link]').forEach(b=>b.classList.toggle('active',b.dataset.settingsLink===id));}
function updateSettingsSectionFromScroll(){if(state.screen!=='app'||state.page!=='settings')return;const sections=[...document.querySelectorAll('[data-settings-section]')];if(!sections.length)return;let active=sections[0].dataset.settingsSection;const marker=150;sections.forEach(section=>{if(section.getBoundingClientRect().top<=marker)active=section.dataset.settingsSection});setSettingsSection(active);}
function bindSettingsNavigation(){window.removeEventListener('scroll',updateSettingsSectionFromScroll);if(state.screen!=='app'||state.page!=='settings')return;document.querySelectorAll('[data-settings-link]').forEach(button=>button.onclick=e=>{e.preventDefault();const id=button.dataset.settingsLink,target=document.querySelector(`[data-settings-section="${id}"]`);if(target){setSettingsSection(id);target.scrollIntoView({behavior:'smooth',block:'start'});}});window.addEventListener('scroll',updateSettingsSectionFromScroll,{passive:true});updateSettingsSectionFromScroll();}
function bindNotifications(){const list=notifications();document.querySelectorAll('[data-status-index]').forEach(b=>b.onclick=()=>setStatus(list[Number(b.dataset.statusIndex)].activity,b.dataset.status));document.querySelectorAll('[data-notification-index]').forEach(b=>b.onclick=()=>{state.selected=list[Number(b.dataset.notificationIndex)].activity;state.notificationOpen=false;render()});}

async function enterDemoAccount(credentials=DEMO){const result=await api.login(credentials);document.cookie='demo_session=1; path=/; SameSite=Lax';state.user=result.user;state.activities=(await api.activities()).activities;state.screen='app';state.page='dashboard';state.theme=result.user.theme||state.theme;render();toast('Miło Cię widzieć!')}
async function login(e){e.preventDefault();const form=e.currentTarget.closest?.('form')||e.currentTarget,button=form.querySelector('.auth-submit'),credentials=Object.fromEntries(new FormData(form));credentials.email=String(credentials.email||'').trim().toLowerCase();credentials.password=String(credentials.password||'');button.disabled=true;button.textContent='Logowanie…';try{if(credentials.email!==DEMO.email||credentials.password!==DEMO.password)throw new Error(`Użyj danych: ${DEMO.email} / ${DEMO.password}`);await enterDemoAccount(credentials)}catch(err){document.querySelector('#auth-error').innerHTML=`<div class="inline-alert error">${icon('close')}<span>${esc(err.message)}</span></div>`;button.disabled=false;button.innerHTML=`Zaloguj się ${icon('arrow')}`;}}
async function logout(){try{await api.logout()}catch{}state.screen='landing';state.user=null;state.activities=[];state.selected=null;render();}
async function setStatus(a,status){try{await api.status(a.id,status);a.status=status;render();toast(status==='completed'?'Świetnie! Trening został zaliczony.':'Trening nie został zaliczony.',status==='completed'?'success':'error')}catch(err){toast(err.message,'error')}}
function changeGoalInput(e){e.preventDefault();const input=document.querySelector('#goal-form input[name="goal"]');if(!input)return;const next=Math.max(1,Math.min(100,Number(input.value||state.user.monthlyActivityGoal||8)+Number(e.currentTarget.dataset.goalDelta)));input.value=next;state.user.monthlyActivityGoal=next;}
async function saveGoal(e){e.preventDefault();const input=e.currentTarget.querySelector('input[name="goal"]'),goal=Math.max(1,Math.min(100,Number(input?.value||state.user.monthlyActivityGoal||8)));if(!Number.isFinite(goal))return toast('Cel musi wynosić od 1 do 100.','error');try{await api.goal({monthlyActivityGoal:goal});state.user.monthlyActivityGoal=goal;render();toast('Miesięczny cel został zapisany.')}catch(err){toast(err.message,'error')}}
async function saveProfile(e){e.preventDefault();const form=e.currentTarget,fd=new FormData(form),payload={name:fd.get('name'),email:fd.get('email'),defaultLocation:fd.get('defaultLocation'),defaultPostalCode:fd.get('defaultPostalCode'),defaultLocationLat:fd.get('defaultLocationLat')||null,defaultLocationLng:fd.get('defaultLocationLng')||null,preferredRadiusKm:Number(fd.get('preferredRadiusKm')),theme:state.theme};try{if(payload.defaultLocation&&(!payload.defaultLocationLat||!payload.defaultLocationLng)){const g=await api.geocode({address:payload.defaultLocation,postalCode:payload.defaultPostalCode});payload.defaultLocationLat=g.location.lat;payload.defaultLocationLng=g.location.lng;}await api.profile(payload);Object.assign(state.user,payload);render();toast('Ustawienia zostały zapisane.')}catch(err){toast(err.message,'error')}}
function syncProfileForm(){const form=document.querySelector('#profile-form');if(!form||!state.user)return state.user;const fd=new FormData(form);Object.assign(state.user,{name:fd.get('name')||state.user.name,email:fd.get('email')||state.user.email,defaultLocation:fd.get('defaultLocation')||'',defaultPostalCode:fd.get('defaultPostalCode')||'',defaultLocationLat:fd.get('defaultLocationLat')||null,defaultLocationLng:fd.get('defaultLocationLng')||null,preferredRadiusKm:Number(fd.get('preferredRadiusKm')||state.user.preferredRadiusKm||25),theme:state.theme});return state.user;}
function useGeolocation(settings=false){if(!navigator.geolocation)return toast('Przeglądarka nie obsługuje geolokalizacji.','error');navigator.geolocation.getCurrentPosition(async({coords})=>{try{const r=await api.reverse({lat:coords.latitude,lng:coords.longitude});if(settings){const form=document.querySelector('#profile-form'),postal=r.location.postalCode||'';Object.assign(state.user,{defaultLocation:r.location.address,defaultPostalCode:postal,defaultLocationLat:coords.latitude,defaultLocationLng:coords.longitude});if(form){form.defaultLocation.value=state.user.defaultLocation;form.defaultPostalCode.value=state.user.defaultPostalCode;form.defaultLocationLat.value=state.user.defaultLocationLat;form.defaultLocationLng.value=state.user.defaultLocationLng;}}else{Object.assign(state.modalForm,{locationAddress:r.location.address,postalCode:r.location.postalCode||state.modalForm.postalCode,locationLat:coords.latitude,locationLng:coords.longitude});renderOverlay();}toast('Lokalizacja została odczytana.')}catch(err){toast(err.message,'error')}},()=>toast('Nie udało się pobrać lokalizacji.','error'),{timeout:8000,maximumAge:300000});}

function syncModalForm(){const form=document.querySelector('#activity-form');if(!form)return state.modalForm;const fd=new FormData(form),f=state.modalForm,newAddress=fd.get('locationAddress'),newPostal=fd.get('postalCode');if(newAddress!==f.locationAddress||newPostal!==f.postalCode){f.locationLat=null;f.locationLng=null;}['title','activityDate','startTime','endTime','note'].forEach(k=>f[k]=fd.get(k));f.locationAddress=newAddress;f.postalCode=newPostal;f.searchRadiusKm=Number(fd.get('searchRadiusKm'));f.repeatWeekly=fd.get('repeatWeekly')==='on';f.repeatCount=Number(fd.get('repeatCount')||4);if(f.activityType==='running'){f.details.targetDistanceKm=Number(fd.get('targetDistanceKm'));f.details.paceMinPerKm=Number(fd.get('paceMinPerKm'));}return f;}
async function resolveModalLocation(){const f=syncModalForm();if(f.locationLat!=null&&f.locationLng!=null)return f;const g=await api.geocode({address:f.locationAddress,postalCode:f.postalCode});f.locationLat=g.location.lat;f.locationLng=g.location.lng;return f;}
function closeOverlay(){state.modalForm=null;state.modalOriginal=null;state.selected=null;renderOverlay();}
function bindOverlay(){
  document.querySelectorAll('[data-close-modal]').forEach(b=>b.onclick=e=>{e.preventDefault();e.stopPropagation();closeOverlay()});
  const backdrop=document.querySelector('.modal-backdrop');
  backdrop?.addEventListener('click',e=>{if(e.target===backdrop){e.preventDefault();e.stopPropagation()}});
  document.querySelector('.modal')?.addEventListener('click',e=>e.stopPropagation());
  document.querySelectorAll('[data-sport]').forEach(b=>b.onclick=e=>{e.preventDefault();e.stopPropagation();syncModalForm();const old=state.modalForm.activityType;state.modalForm.activityType=b.dataset.sport;const defaults={running:'Poranny bieg',basketball:'Koszykówka',swimming:'Trening pływacki'};if(state.modalForm.title===defaults[old])state.modalForm.title=defaults[b.dataset.sport];state.places=[];renderOverlay()});
  document.querySelectorAll('[data-court]').forEach(b=>b.onclick=e=>{e.preventDefault();e.stopPropagation();syncModalForm();state.modalForm.details.courtType=b.dataset.court;renderOverlay()});
  document.querySelector('#modal-geolocation')?.addEventListener('click',e=>{e.preventDefault();e.stopPropagation();useGeolocation(false)});
  document.querySelector('#find-places')?.addEventListener('click',e=>{e.preventDefault();e.stopPropagation();findPlaces()});
  document.querySelector('#check-weather')?.addEventListener('click',e=>{e.preventDefault();e.stopPropagation();checkWeather()});
  document.querySelector('#activity-form')?.addEventListener('submit',saveActivity);
  document.querySelector('#activity-form')?.addEventListener('input',syncModalForm);
  document.querySelector('#activity-form')?.addEventListener('change',syncModalForm);
  document.querySelectorAll('[data-place]').forEach(b=>b.onclick=e=>{e.preventDefault();e.stopPropagation();const p=state.places.find(x=>String(x.id)===b.dataset.place);Object.assign(state.modalForm,{locationAddress:p.address,postalCode:p.postalCode||state.modalForm.postalCode,locationLat:Number(p.lat),locationLng:Number(p.lng)});state.modalForm.details.selectedPlaceId=p.id;renderOverlay()});
  document.querySelector('#delete-activity')?.addEventListener('click',deleteActivity);
  document.querySelector('#edit-activity')?.addEventListener('click',e=>{e.preventDefault();e.stopPropagation();const a=state.selected;state.selected=null;openActivity(a.activityDate,a)});
  document.querySelector('#regenerate-route')?.addEventListener('click',regenerateRoute);
}
async function findPlaces(){try{const f=await resolveModalLocation(),result=await api.places({type:f.activityType==='swimming'?'pool':'hall',lat:f.locationLat,lng:f.locationLng,radiusKm:f.searchRadiusKm});state.places=result.places;renderOverlay();if(!state.places.length)toast('Nie znaleziono miejsc w tym promieniu.','error')}catch(err){toast(err.message,'error')}}
async function checkWeather(){try{const f=await resolveModalLocation(),result=await api.weather({lat:f.locationLat,lng:f.locationLng,date:f.activityDate,from:f.startTime,to:f.endTime});state.weather=result.weather;renderOverlay();toast('Prognoza została pobrana.')}catch(err){toast(err.message,'error')}}
function fallbackWeather(){return {temperature:18,windSpeed:8,precipitation:0,thunderstorm:false,source:'demo'};}
function fallbackRoute(f){const lat=Number(f.locationLat)||52.2297,lng=Number(f.locationLng)||21.0122,delta=(Number(f.details.targetDistanceKm)||5)/111/8;return {actualDistanceKm:Number(f.details.targetDistanceKm)||5,estimatedDurationMinutes:Math.round((Number(f.details.targetDistanceKm)||5)*(Number(f.details.paceMinPerKm)||6)),route:{type:'Feature',properties:{variant:0,demo:true},geometry:{type:'LineString',coordinates:[[lng,lat],[lng+delta,lat+delta],[lng,lat]]}}};}
function fallbackRecommendation(){return {status:'good',message:'Tryb demo: aktywność dodana bez blokowania na zewnętrzne API.'};}
async function saveActivity(e){
  e.preventDefault();
  e.stopPropagation();
  const button=e.currentTarget.querySelector('.modal-footer .primary-button'),editing=Boolean(state.modalOriginal);
  button.disabled=true;
  button.textContent='Zapisywanie…';
  try{
    const f=await resolveModalLocation();
    if(!/^\d{2}-\d{3}$/.test(f.postalCode))throw new Error('Podaj kod pocztowy w formacie 00-000.');
    if(f.endTime<=f.startTime)throw new Error('Godzina zakończenia musi być późniejsza niż rozpoczęcia.');
    let payload=structuredClone(f);
    if(f.activityType==='running'){
      let route;
      try{route=await api.route({lat:f.locationLat,lng:f.locationLng,targetDistanceKm:f.details.targetDistanceKm,paceMinPerKm:f.details.paceMinPerKm})}
      catch{route=fallbackRoute(f)}
      Object.assign(payload.details,{actualDistanceKm:route.actualDistanceKm,estimatedDurationMinutes:route.estimatedDurationMinutes,routeGeojson:route.route});
    }
    let weather=state.weather;
    if(!weather){try{weather=(await api.weather({lat:f.locationLat,lng:f.locationLng,date:f.activityDate,from:f.startTime,to:f.endTime})).weather}catch{weather=fallbackWeather()}}
    let recommendation;
    try{recommendation=(await api.recommendation({activityType:f.activityType,courtType:f.details.courtType,selectedPlace:f.details.selectedPlaceId,weather})).recommendation}
    catch{recommendation=fallbackRecommendation()}
    Object.assign(payload.details,{weather,recommendation});
    if(editing)await api.update(state.modalOriginal.id,payload,true);else await api.create(payload,true);
    state.activities=(await api.activities()).activities;
    state.modalForm=null;
    state.modalOriginal=null;
    render();
    toast(editing?'Aktywność została zaktualizowana.':'Aktywność jest już w kalendarzu!')
  }catch(err){
    toast(err.message,'error');
    button.disabled=false;
    button.innerHTML=`${icon('check')} ${editing?'Zapisz zmiany':'Dodaj do kalendarza'}`;
  }
}
async function deleteActivity(){const a=state.selected;if(!confirm(`Usunąć „${a.title}”?`))return;try{await api.remove(a.id);state.activities=state.activities.filter(x=>x.id!==a.id);state.selected=null;render();toast('Aktywność została usunięta.')}catch(err){toast(err.message,'error')}}
async function regenerateRoute(){const a=state.selected,button=document.querySelector('#regenerate-route');button.disabled=true;try{const variant=Number(a.details?.routeGeojson?.properties?.variant||0)+1,route=await api.route({lat:a.locationLat,lng:a.locationLng,targetDistanceKm:Number(a.details?.targetDistanceKm||a.details?.actualDistanceKm||5),paceMinPerKm:Number(a.details?.paceMinPerKm||6),variant});a.details={...a.details,actualDistanceKm:route.actualDistanceKm,estimatedDurationMinutes:route.estimatedDurationMinutes,routeGeojson:route.route};await api.update(a.id,a,true);renderOverlay();toast('Wygenerowano nowy wariant trasy.')}catch(err){toast(err.message,'error');button.disabled=false}}

async function init(){applyTheme();try{const me=await api.me();state.user=me.user;state.activities=(await api.activities()).activities;state.screen='app';state.theme=me.user.theme||state.theme;}catch{state.screen='landing'}render();}
init();
